package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
public class CSVFormatTest {

    @Mock
    private QuoteMode quoteModeMock;

    @Test
    public void testWithQuoteMode() {
        // Create a CSVFormat instance
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Call the withQuoteMode method with the mocked QuoteMode
        CSVFormat newCsvFormat = csvFormat.withQuoteMode(quoteModeMock);

        // Assert that the returned CSVFormat has the correct QuoteMode
        assertEquals(quoteModeMock, newCsvFormat.getQuoteMode());
    }
}
